    return (privateKey: privateKey, publicKey: publicKey)
}

// Sign data with a private key
func sign(_ data: Data, using privateKey: SecKey) -> Data {
    var signature: Data?
    let status = SecKeyRawSign(privateKey, kSecPaddingPKCS1SHA256, nil, data, &signature)
    assert(status == errSecSuccess, "Failed to sign data")
    
    guard let signature = signature else {
        fatalError("Failed to generate signature")
    }
    
    return signature
}

// Verify a signature with public key
func verifySignature(signature: Data, data: Data, publicKey: Data) -> Bool {
